/*Table structure for table `user_info` */

DROP TABLE IF EXISTS `user_info`;

CREATE TABLE `user_info` (
  `user_id` int(11) NOT NULL COMMENT '用户ID',
  `user_name` varchar(20) NOT NULL COMMENT '用户姓名',
  `gender` int(11) DEFAULT NULL COMMENT '用户性别',
  `age` int(11) DEFAULT NULL COMMENT '用户年龄',
  `phone` varchar(20) DEFAULT NULL COMMENT '用户手机号',
  `province` varchar(30) DEFAULT NULL COMMENT '省份',
  `city` varchar(30) DEFAULT NULL COMMENT '用户所在城市',
  `device_type` varchar(30) NOT NULL COMMENT '设备类型',
  `active` int(11) NOT NULL COMMENT '用户活跃度',
  `modify_date` varchar(30) NOT NULL COMMENT '修改日期',
  `create_date` varchar(30) NOT NULL COMMENT '创建日期',
  `account` varchar(20) NOT NULL COMMENT '用户账号',
  `password` varchar(20) NOT NULL COMMENT '用户密码',
  PRIMARY KEY (`user_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

